-- ----------------------------------------------------------------------------
-- vw_cities: Cities provide the outer spatial boundary for TSP instances.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_cities CASCADE;
CREATE VIEW vw_cities WITH (security_invoker = ON) AS
SELECT
  t.city_id,                                                                    -- Stable city identifier.
  calc_cities_name(t.city_id) AS name,                                          -- Human-readable city label.
  t.display_name,                                                               -- Human-readable city name.
  t.country_code,                                                               -- ISO-style country code for the city.
  t.coordinate_system,                                                          -- Coordinate convention used by addresses in this city.
  t.description                                                                 -- Purpose of the city fixture.
FROM cities t;

-- ----------------------------------------------------------------------------
-- vw_neighborhoods: Neighborhoods partition a city into first-class spatial clusters.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_neighborhoods CASCADE;
CREATE VIEW vw_neighborhoods WITH (security_invoker = ON) AS
SELECT
  t.neighborhood_id,                                                            -- Stable neighborhood identifier.
  calc_neighborhoods_name(t.neighborhood_id) AS name,                           -- Human-readable neighborhood label.
  t.display_name,                                                               -- Human-readable neighborhood name.
  t.city,                                                                       -- City containing this neighborhood.
  calc_neighborhoods_city_name(t.neighborhood_id) AS city_name,                 -- Display name of the containing city.
  t.cluster_kind,                                                               -- Semantic role of the neighborhood in the initial fixture.
  t.is_quotient_node,                                                           -- Whether the neighborhood is currently used as a quotient-graph node.
  t.quotient_node_kind,                                                         -- Boundary object kind.
  t.required_boundary_degree,                                                   -- Required external incidence in the quotient cycle.
  t.quotient_scope_id                                                           -- Instance scope without introducing a relationship cycle.
FROM neighborhoods t;

-- ----------------------------------------------------------------------------
-- vw_addresses: Addresses are visitable physical locations. Coordinates support visualization; edge costs remain explicit graph data.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_addresses CASCADE;
CREATE VIEW vw_addresses WITH (security_invoker = ON) AS
SELECT
  t.address_id,                                                                 -- Stable address identifier.
  calc_addresses_name(t.address_id) AS name,                                    -- Human-readable address label.
  t.street_label,                                                               -- Human-readable street or place label.
  t.neighborhood,                                                               -- Neighborhood containing this address.
  calc_addresses_neighborhood_name(t.address_id) AS neighborhood_name,          -- Display name of the containing neighborhood.
  calc_addresses_city(t.address_id) AS city,                                    -- City reached through the address's neighborhood.
  t.x_coordinate,                                                               -- Local X coordinate for visualization and later geometric experiments.
  t.y_coordinate,                                                               -- Local Y coordinate for visualization and later geometric experiments.
  t.is_depot_candidate                                                          -- Whether this address may serve as a depot.
FROM addresses t;

-- ----------------------------------------------------------------------------
-- vw_tsp_instances: One finite Traveling Salesman problem instance over required city addresses.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_instances CASCADE;
CREATE VIEW vw_tsp_instances WITH (security_invoker = ON) AS
SELECT
  t.tsp_instance_id,                                                            -- Stable TSP instance identifier.
  calc_tsp_instances_name(t.tsp_instance_id) AS name,                           -- Human-readable instance label.
  t.display_name,                                                               -- Human-readable TSP instance name.
  t.city,                                                                       -- City containing the instance.
  t.depot_address,                                                              -- Address fixed as the tour depot.
  t.distance_model,                                                             -- Interpretation of TravelEdges.TravelCost.
  t.is_symmetric,                                                               -- Whether each canonical edge cost applies in both directions.
  t.status,                                                                     -- Current semantic-normalization status.
  t.search_policy,                                                              -- Research policy governing when search is allowed.
  calc_tsp_instances_count_of_stops(t.tsp_instance_id) AS count_of_stops,       -- Number of normalized instance-stop rows.
  calc_tsp_instances_count_of_required_stops(t.tsp_instance_id) AS count_of_required_stops,-- Number of required visit stops.
  calc_tsp_instances_count_of_travel_edges(t.tsp_instance_id) AS count_of_travel_edges,-- Number of canonical undirected travel edges.
  calc_tsp_instances_count_of_inadmissible_edges(t.tsp_instance_id) AS count_of_inadmissible_edges,-- Edge rows failing canonical pair, endpoint, availability, or instance checks.
  calc_tsp_instances_count_of_non_unique_edge_pair_rows(t.tsp_instance_id) AS count_of_non_unique_edge_pair_rows,-- Rows participating in a duplicated canonical unordered edge pair.
  calc_tsp_instances_expected_undirected_edge_count(t.tsp_instance_id) AS expected_undirected_edge_count,-- n(n-1)/2 expected edges for a complete undirected graph.
  calc_tsp_instances_is_complete_undirected_graph(t.tsp_instance_id) AS is_complete_undirected_graph,-- Whether the instance has the expected edge count, no inadmissible rows, and no duplicated unordered pair rows.
  t.notes                                                                       -- Scope and caveats for the instance.
FROM tsp_instances t;

