  calc_tsp_graph_invariant_checks_actual_complete_undirected_grap(t.tsp_graph_invariant_check_id) AS actual_complete_undirected_graph,-- Derived graph-completeness status.
  t.expected_travel_edge_count,                                                 -- Expected raw edge-row count.
  calc_tsp_graph_invariant_checks_actual_travel_edge_count(t.tsp_graph_invariant_check_id) AS actual_travel_edge_count,-- Derived raw edge-row count.
  t.expected_non_unique_edge_pair_rows,                                         -- Expected number of rows participating in duplicated pair keys.
  calc_tsp_graph_invariant_checks_actual_non_unique_edge_pair_row(t.tsp_graph_invariant_check_id) AS actual_non_unique_edge_pair_rows,-- Derived duplicated-pair row count.
  calc_tsp_graph_invariant_checks_is_passing(t.tsp_graph_invariant_check_id) AS is_passing-- Whether all graph expectations agree with derived values.
