  calc_instance_stops_address_name(t.instance_stop_id) AS address_name,         -- Human-readable address label.
  calc_instance_stops_address_city(t.instance_stop_id) AS address_city,         -- City reached through the selected address.
  calc_instance_stops_neighborhood(t.instance_stop_id) AS neighborhood,         -- Neighborhood of the selected address.
  calc_instance_stops_x_coordinate(t.instance_stop_id) AS x_coordinate,         -- X coordinate of the selected address.
  calc_instance_stops_y_coordinate(t.instance_stop_id) AS y_coordinate,         -- Y coordinate of the selected address.
  calc_instance_stops_is_within_instance_city(t.instance_stop_id) AS is_within_instance_city,-- Whether the selected address belongs to the instance city.
  calc_instance_stops_is_depot(t.instance_stop_id) AS is_depot,                 -- Whether this stop is the instance depot.
  calc_instance_stops_count_of_canonical_edges_from(t.instance_stop_id) AS count_of_canonical_edges_from,-- Canonical edge rows whose first endpoint is this stop.
  calc_instance_stops_count_of_canonical_edges_to(t.instance_stop_id) AS count_of_canonical_edges_to,-- Canonical edge rows whose second endpoint is this stop.
  calc_instance_stops_count_of_incident_edges(t.instance_stop_id) AS count_of_incident_edges,-- Total canonical incident edge rows at this stop.
  calc_instance_stops_count_of_admissible_edges_from(t.instance_stop_id) AS count_of_admissible_edges_from,-- Admissible edge rows whose first endpoint is this stop.
  calc_instance_stops_count_of_admissible_edges_to(t.instance_stop_id) AS count_of_admissible_edges_to,-- Admissible edge rows whose second endpoint is this stop.
  calc_instance_stops_count_of_admissible_incident_edges(t.instance_stop_id) AS count_of_admissible_incident_edges-- Total currently admissible edges incident to this stop.
FROM instance_stops t;

-- ----------------------------------------------------------------------------
-- vw_travel_edges: Canonical undirected weighted edges between instance stops. The edge entity resolves the address-to-address many-to-many relation.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_travel_edges CASCADE;
CREATE VIEW vw_travel_edges WITH (security_invoker = ON) AS
SELECT
  t.travel_edge_id,                                                             -- Stable canonical edge identifier.
  calc_travel_edges_name(t.travel_edge_id) AS name,                             -- Display alias for the edge.
  t.tsp_instance,                                                               -- TSP instance owning the edge.
  t.from_stop,                                                                  -- First canonical endpoint.
  t.to_stop,                                                                    -- Second canonical endpoint.
  t.distance_meters,                                                            -- Observed or supplied travel distance for the edge.
  t.travel_cost,                                                                -- Optimization cost used by the initial TSP objective.
  t.is_available,                                                               -- Whether the edge remains available after current normalization.
  t.edge_source,                                                                -- Provenance of the edge weight.
  t.canonical_pair_key,                                                         -- Canonical unordered endpoint identity supplied as data and checked against the two endpoint rows.
  calc_travel_edges_expected_canonical_pair_key(t.travel_edge_id) AS expected_canonical_pair_key,-- Endpoint-derived canonical pair key used to verify the supplied pair identity.
  calc_travel_edges_is_canonical_pair_key_correct(t.travel_edge_id) AS is_canonical_pair_key_correct,-- Whether CanonicalPairKey agrees with the sorted endpoint identities.
  calc_travel_edges_is_canonical_endpoint_order(t.travel_edge_id) AS is_canonical_endpoint_order,-- Whether the stored FromStop/ToStop order is the declared canonical lexical order.
  calc_travel_edges_pair_multiplicity(t.travel_edge_id) AS pair_multiplicity,   -- Number of edge rows in this instance carrying the same canonical unordered pair key.
  calc_travel_edges_is_unique_canonical_pair(t.travel_edge_id) AS is_unique_canonical_pair,-- Whether exactly one edge row represents this unordered stop pair in the instance.
  calc_travel_edges_from_tsp_instance(t.travel_edge_id) AS from_tsp_instance,   -- Instance of the first endpoint.
  calc_travel_edges_to_tsp_instance(t.travel_edge_id) AS to_tsp_instance,       -- Instance of the second endpoint.
  calc_travel_edges_is_self_loop(t.travel_edge_id) AS is_self_loop,             -- Whether both endpoints are the same stop.
  calc_travel_edges_is_within_instance(t.travel_edge_id) AS is_within_instance, -- Whether the edge and both endpoints belong to one instance.
  calc_travel_edges_is_admissible(t.travel_edge_id) AS is_admissible            -- First-order edge admissibility including availability, instance membership, canonical endpoint order, correct pair identity, and pair uniqueness.
FROM travel_edges t;

-- ----------------------------------------------------------------------------
-- vw_candidate_tours: Explicit candidate tours. Validity is derived; optimality is deliberately not inferred.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_candidate_tours CASCADE;
CREATE VIEW vw_candidate_tours WITH (security_invoker = ON) AS
SELECT
  t.candidate_tour_id,                                                          -- Stable candidate-tour identifier.
  calc_candidate_tours_name(t.candidate_tour_id) AS name,                       -- Human-readable tour label.
  t.display_name,                                                               -- Human-readable candidate-tour name.
  t.tsp_instance,                                                               -- TSP instance evaluated by this candidate.
  t.candidate_kind,                                                             -- Role of this candidate in the fixture.
  t.search_branches_explored,                                                   -- Branches explored to obtain this candidate; zero means supplied witness, not solved.
  t.backtrack_count,                                                            -- Backtracking performed to obtain this candidate.
  calc_candidate_tours_required_stop_count(t.candidate_tour_id) AS required_stop_count,-- Required stop count supplied by the instance.
  calc_candidate_tours_count_of_tour_stops(t.candidate_tour_id) AS count_of_tour_stops,-- Number of ordered tour-stop rows.
  calc_candidate_tours_count_of_tour_legs(t.candidate_tour_id) AS count_of_tour_legs,-- Number of ordered tour-leg rows.
  calc_candidate_tours_count_of_non_unique_visits(t.candidate_tour_id) AS count_of_non_unique_visits,-- Tour-stop rows whose instance stop appears more than once.
  calc_candidate_tours_count_of_non_unique_sequences(t.candidate_tour_id) AS count_of_non_unique_sequences,-- Tour-stop rows whose sequence position is duplicated.
  calc_candidate_tours_count_of_out_of_instance_stops(t.candidate_tour_id) AS count_of_out_of_instance_stops,-- Tour stops that do not belong to the candidate's instance.
  calc_candidate_tours_count_of_non_required_stops(t.candidate_tour_id) AS count_of_non_required_stops,-- Tour stops not marked required by the instance.
  calc_candidate_tours_count_of_depot_stops(t.candidate_tour_id) AS count_of_depot_stops,-- Number of depot visits in the ordered stop list.
  calc_candidate_tours_count_of_depot_position_violations(t.candidate_tour_id) AS count_of_depot_position_violations,-- Depot rows not placed at sequence position one.
  calc_candidate_tours_count_of_invalid_legs(t.candidate_tour_id) AS count_of_invalid_legs,-- Tour legs failing membership, sequence, edge, or instance checks.
  calc_candidate_tours_count_of_cycle_degree_violations(t.candidate_tour_id) AS count_of_cycle_degree_violations,-- Ordered visits lacking exactly one incoming and one outgoing candidate leg.
  calc_candidate_tours_count_of_non_unique_leg_orders(t.candidate_tour_id) AS count_of_non_unique_leg_orders,-- Leg rows whose LegOrder is duplicated within the candidate.
  calc_candidate_tours_total_travel_cost(t.candidate_tour_id) AS total_travel_cost,-- Sum of validated tour-leg costs.
  calc_candidate_tours_is_hamiltonian_cycle_witness(t.candidate_tour_id) AS is_hamiltonian_cycle_witness,-- Whether the supplied ordered rows form one globally covered Hamiltonian cycle for the declared instance.
  calc_candidate_tours_count_of_passing_optimality_certificates(t.candidate_tour_id) AS count_of_passing_optimality_certificates,-- Passing finite-instance optimality certificates attached to this candidate.
  calc_candidate_tours_is_optimality_proved(t.candidate_tour_id) AS is_optimality_proved,-- Whether at least one passing finite-instance optimality certificate closes this candidate's scope.
  calc_candidate_tours_residual_claim(t.candidate_tour_id) AS residual_claim    -- Honest current epistemic status of the candidate.
FROM candidate_tours t;

-- ----------------------------------------------------------------------------
-- vw_tour_stops: Ordered candidate-tour visits. Multiplicity and sequence uniqueness are derived from the row set.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tour_stops CASCADE;
CREATE VIEW vw_tour_stops WITH (security_invoker = ON) AS
SELECT
  t.tour_stop_id,                                                               -- Stable ordered tour-stop identifier.
  calc_tour_stops_name(t.tour_stop_id) AS name,                                 -- Display alias for the ordered visit.
  t.candidate_tour,                                                             -- Candidate tour containing the ordered visit.
  t.instance_stop,                                                              -- Instance stop visited at this position.
  t.sequence_position,                                                          -- One-based position in the ordered visit list.
  calc_tour_stops_tour_tsp_instance(t.tour_stop_id) AS tour_tsp_instance,       -- TSP instance owned by the candidate tour.
  calc_tour_stops_stop_tsp_instance(t.tour_stop_id) AS stop_tsp_instance,       -- TSP instance owning the visited stop.
  calc_tour_stops_stop_is_required(t.tour_stop_id) AS stop_is_required,         -- Whether the visited stop is required.
  calc_tour_stops_stop_is_depot(t.tour_stop_id) AS stop_is_depot,               -- Whether the visited stop is the depot.
  calc_tour_stops_is_in_tour_instance(t.tour_stop_id) AS is_in_tour_instance,   -- Whether the visited stop belongs to the candidate's instance.
  calc_tour_stops_visit_multiplicity(t.tour_stop_id) AS visit_multiplicity,     -- Number of times this instance stop appears in the candidate.
  calc_tour_stops_sequence_multiplicity(t.tour_stop_id) AS sequence_multiplicity,-- Number of rows using this sequence position in the candidate.
  calc_tour_stops_is_unique_visit(t.tour_stop_id) AS is_unique_visit,           -- Whether this stop appears exactly once.
  calc_tour_stops_is_unique_sequence(t.tour_stop_id) AS is_unique_sequence,     -- Whether this sequence position appears exactly once.
  calc_tour_stops_is_depot_at_first_position(t.tour_stop_id) AS is_depot_at_first_position,-- Non-depot rows pass automatically; the depot must be position one.
  calc_tour_stops_count_of_outgoing_legs(t.tour_stop_id) AS count_of_outgoing_legs,-- Tour-leg rows in this candidate whose FromTourStop is this ordered visit.
  calc_tour_stops_count_of_incoming_legs(t.tour_stop_id) AS count_of_incoming_legs,-- Tour-leg rows in this candidate whose ToTourStop is this ordered visit.
  calc_tour_stops_has_exactly_one_outgoing_leg(t.tour_stop_id) AS has_exactly_one_outgoing_leg,-- Whether this ordered visit has exactly one outgoing candidate leg.
  calc_tour_stops_has_exactly_one_incoming_leg(t.tour_stop_id) AS has_exactly_one_incoming_leg,-- Whether this ordered visit has exactly one incoming candidate leg.
  calc_tour_stops_is_cycle_degree_satisfied(t.tour_stop_id) AS is_cycle_degree_satisfied-- Whether this ordered visit participates in exactly one incoming and one outgoing transition.
FROM tour_stops t;

-- ----------------------------------------------------------------------------
-- vw_tour_legs: Ordered directed traversal legs bound to canonical undirected travel edges.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tour_legs CASCADE;
CREATE VIEW vw_tour_legs WITH (security_invoker = ON) AS
SELECT
  t.tour_leg_id,                                                                -- Stable ordered tour-leg identifier.
  calc_tour_legs_name(t.tour_leg_id) AS name,                                   -- Display alias for the leg.
  t.candidate_tour,                                                             -- Candidate tour containing the leg.
  t.from_tour_stop,                                                             -- Ordered visit at the start of the leg.
  t.to_tour_stop,                                                               -- Ordered visit at the end of the leg.
  t.travel_edge,                                                                -- Canonical undirected edge traversed by the leg.
  t.leg_order,                                                                  -- One-based order of the leg.
  calc_tour_legs_tour_tsp_instance(t.tour_leg_id) AS tour_tsp_instance,         -- TSP instance owned by the candidate tour.
  calc_tour_legs_required_stop_count(t.tour_leg_id) AS required_stop_count,     -- Required stop count reached through the candidate's TSP instance and used to recognize the closing leg.
  calc_tour_legs_from_tour_candidate(t.tour_leg_id) AS from_tour_candidate,     -- Candidate tour owning the from visit.
  calc_tour_legs_to_tour_candidate(t.tour_leg_id) AS to_tour_candidate,         -- Candidate tour owning the to visit.
  calc_tour_legs_from_instance_stop(t.tour_leg_id) AS from_instance_stop,       -- Instance stop at the start of the leg.
  calc_tour_legs_to_instance_stop(t.tour_leg_id) AS to_instance_stop,           -- Instance stop at the end of the leg.
  calc_tour_legs_from_sequence_position(t.tour_leg_id) AS from_sequence_position,-- Sequence position at the start of the leg.
  calc_tour_legs_to_sequence_position(t.tour_leg_id) AS to_sequence_position,   -- Sequence position at the end of the leg.
  calc_tour_legs_edge_tsp_instance(t.tour_leg_id) AS edge_tsp_instance,         -- TSP instance owning the selected edge.
  calc_tour_legs_edge_from_stop(t.tour_leg_id) AS edge_from_stop,               -- First canonical edge endpoint.
  calc_tour_legs_edge_to_stop(t.tour_leg_id) AS edge_to_stop,                   -- Second canonical edge endpoint.
  calc_tour_legs_edge_travel_cost(t.tour_leg_id) AS edge_travel_cost,           -- Optimization cost of the selected edge.
  calc_tour_legs_edge_is_admissible(t.tour_leg_id) AS edge_is_admissible,       -- Whether the selected edge passes first-order normalization.
  calc_tour_legs_leg_order_multiplicity(t.tour_leg_id) AS leg_order_multiplicity,-- Number of leg rows in this candidate carrying the same LegOrder.
  calc_tour_legs_is_unique_leg_order(t.tour_leg_id) AS is_unique_leg_order,     -- Whether this leg order appears exactly once in the candidate.
  calc_tour_legs_is_candidate_membership_valid(t.tour_leg_id) AS is_candidate_membership_valid,-- Whether both ordered visits belong to this candidate.
  calc_tour_legs_is_sequence_transition(t.tour_leg_id) AS is_sequence_transition,-- Whether the leg follows the next visit or closes the route from n back to one.
  calc_tour_legs_is_edge_endpoint_match(t.tour_leg_id) AS is_edge_endpoint_match,-- Whether the directed leg traverses the selected undirected edge in either direction.
  calc_tour_legs_is_in_tour_instance(t.tour_leg_id) AS is_in_tour_instance,     -- Whether the edge belongs to the candidate's TSP instance.
  calc_tour_legs_is_valid(t.tour_leg_id) AS is_valid,                           -- Whether the leg passes candidate membership, sequence, endpoint, instance, admissibility, and unique-order checks.
  calc_tour_legs_travel_cost(t.tour_leg_id) AS travel_cost                      -- Cost contributed by a valid leg; invalid legs contribute zero and are counted separately.
FROM tour_legs t;

-- ----------------------------------------------------------------------------
-- vw_local_degree_bounds: One degree-two lower-bound witness per required stop. Each row names two incident edges and proves all other incident edges are no cheaper than the second selected edge.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_local_degree_bounds CASCADE;
CREATE VIEW vw_local_degree_bounds WITH (security_invoker = ON) AS
SELECT
  t.local_degree_bound_id,                                                      -- Stable local-bound identifier.
  calc_local_degree_bounds_name(t.local_degree_bound_id) AS name,               -- Display alias for the local bound.
  t.tsp_instance,                                                               -- Instance whose tour degree requirement is being bounded.
  t.instance_stop,                                                              -- Required stop receiving the local degree-two bound.
  t.first_edge,                                                                 -- Cheapest selected incident edge.
  t.second_edge,                                                                -- Second-cheapest selected incident edge.
  calc_local_degree_bounds_stop_tsp_instance(t.local_degree_bound_id) AS stop_tsp_instance,-- Instance owning the bounded stop.
  calc_local_degree_bounds_stop_admissible_incident_edge_count(t.local_degree_bound_id) AS stop_admissible_incident_edge_count,-- Current admissible incident-edge count at the stop.
  calc_local_degree_bounds_first_edge_from_stop(t.local_degree_bound_id) AS first_edge_from_stop,-- First selected edge's canonical first endpoint.
  calc_local_degree_bounds_first_edge_to_stop(t.local_degree_bound_id) AS first_edge_to_stop,-- First selected edge's canonical second endpoint.
  calc_local_degree_bounds_second_edge_from_stop(t.local_degree_bound_id) AS second_edge_from_stop,-- Second selected edge's canonical first endpoint.
  calc_local_degree_bounds_second_edge_to_stop(t.local_degree_bound_id) AS second_edge_to_stop,-- Second selected edge's canonical second endpoint.
  calc_local_degree_bounds_first_edge_cost(t.local_degree_bound_id) AS first_edge_cost,-- Cost of the first selected edge.
  calc_local_degree_bounds_second_edge_cost(t.local_degree_bound_id) AS second_edge_cost,-- Cost of the second selected edge.
  calc_local_degree_bounds_is_first_edge_incident(t.local_degree_bound_id) AS is_first_edge_incident,-- Whether the first selected edge is incident to the bounded stop.
  calc_local_degree_bounds_is_second_edge_incident(t.local_degree_bound_id) AS is_second_edge_incident,-- Whether the second selected edge is incident to the bounded stop.
  calc_local_degree_bounds_are_selected_edges_distinct(t.local_degree_bound_id) AS are_selected_edges_distinct,-- Whether the two selected edge rows are distinct.
  calc_local_degree_bounds_are_selected_costs_ordered(t.local_degree_bound_id) AS are_selected_costs_ordered,-- Whether the first selected edge is no more expensive than the second.
  calc_local_degree_bounds_required_dominance_check_count(t.local_degree_bound_id) AS required_dominance_check_count,-- Number of other incident edges that must be compared against the second selected cost.
  calc_local_degree_bounds_count_of_dominance_checks(t.local_degree_bound_id) AS count_of_dominance_checks,-- Represented comparisons against other incident edges.
  calc_local_degree_bounds_count_of_failed_dominance_checks(t.local_degree_bound_id) AS count_of_failed_dominance_checks,-- Dominance comparisons that fail incidence, distinctness, uniqueness, or cost ordering.
  calc_local_degree_bounds_is_two_cheapest_witness(t.local_degree_bound_id) AS is_two_cheapest_witness,-- Whether this row and its child comparisons certify the two cheapest admissible incident edges.
  calc_local_degree_bounds_local_bound_cost(t.local_degree_bound_id) AS local_bound_cost-- Certified sum of the two cheapest incident edge costs; zero when the witness is invalid.
FROM local_degree_bounds t;

-- ----------------------------------------------------------------------------
-- vw_incident_dominance_checks: Witness rows proving every unselected incident edge is at least as expensive as the second edge named by a LocalDegreeBound.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_incident_dominance_checks CASCADE;
CREATE VIEW vw_incident_dominance_checks WITH (security_invoker = ON) AS
SELECT
  t.incident_dominance_check_id,                                                -- Stable dominance-check identifier.
  calc_incident_dominance_checks_name(t.incident_dominance_check_id) AS name,   -- Display alias for the dominance check.
  t.local_degree_bound,                                                         -- Local lower-bound witness being supported.
  t.other_edge,                                                                 -- Unselected incident edge compared against the second selected edge.
  calc_incident_dominance_checks_bound_stop(t.incident_dominance_check_id) AS bound_stop,-- Stop bounded by the parent witness.
  calc_incident_dominance_checks_first_selected_edge(t.incident_dominance_check_id) AS first_selected_edge,-- First edge selected by the parent witness.
  calc_incident_dominance_checks_second_selected_edge(t.incident_dominance_check_id) AS second_selected_edge,-- Second edge selected by the parent witness.
  calc_incident_dominance_checks_second_selected_edge_cost(t.incident_dominance_check_id) AS second_selected_edge_cost,-- Cost of the second selected edge.
  calc_incident_dominance_checks_other_edge_from_stop(t.incident_dominance_check_id) AS other_edge_from_stop,-- Other edge's first endpoint.
  calc_incident_dominance_checks_other_edge_to_stop(t.incident_dominance_check_id) AS other_edge_to_stop,-- Other edge's second endpoint.
  calc_incident_dominance_checks_other_edge_cost(t.incident_dominance_check_id) AS other_edge_cost,-- Cost of the unselected incident edge.
  calc_incident_dominance_checks_other_edge_multiplicity(t.incident_dominance_check_id) AS other_edge_multiplicity,-- Number of comparison rows in the same local witness naming this other edge.
  calc_incident_dominance_checks_is_other_edge_incident(t.incident_dominance_check_id) AS is_other_edge_incident,-- Whether the compared edge is incident to the bounded stop.
  calc_incident_dominance_checks_is_other_edge_unselected(t.incident_dominance_check_id) AS is_other_edge_unselected,-- Whether the compared edge differs from both selected edges.
  calc_incident_dominance_checks_is_other_edge_unique(t.incident_dominance_check_id) AS is_other_edge_unique,-- Whether this unselected edge appears exactly once among the parent's comparisons.
  calc_incident_dominance_checks_is_dominated_by_second_cost(t.incident_dominance_check_id) AS is_dominated_by_second_cost,-- Whether the unselected edge is no cheaper than the second selected edge.
  calc_incident_dominance_checks_is_passing(t.incident_dominance_check_id) AS is_passing-- Whether the comparison is incident, unselected, unique, and cost-dominated.
FROM incident_dominance_checks t;

-- ----------------------------------------------------------------------------
-- vw_instance_lower_bounds: Global lower bounds obtained by summing certified local degree-two bounds and dividing by two because each tour edge is incident to two stops.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_instance_lower_bounds CASCADE;
CREATE VIEW vw_instance_lower_bounds WITH (security_invoker = ON) AS
SELECT
  t.instance_lower_bound_id,                                                    -- Stable instance-lower-bound identifier.
  calc_instance_lower_bounds_name(t.instance_lower_bound_id) AS name,           -- Display alias for the lower bound.
  t.tsp_instance,                                                               -- Instance receiving the lower bound.
  t.bound_kind,                                                                 -- Kind of reusable lower-bound geometry.
  calc_instance_lower_bounds_required_stop_count(t.instance_lower_bound_id) AS required_stop_count,-- Required stop count of the instance.
  calc_instance_lower_bounds_count_of_local_degree_bounds(t.instance_lower_bound_id) AS count_of_local_degree_bounds,-- Local degree-bound rows represented for the instance.
  calc_instance_lower_bounds_count_of_invalid_local_degree_bounds(t.instance_lower_bound_id) AS count_of_invalid_local_degree_bounds,-- Local degree-bound rows that do not carry a valid two-cheapest witness.
  calc_instance_lower_bounds_total_local_degree_bound_cost(t.instance_lower_bound_id) AS total_local_degree_bound_cost,-- Sum of the local two-edge lower bounds across all required stops.
  calc_instance_lower_bounds_lower_bound_cost(t.instance_lower_bound_id) AS lower_bound_cost,-- Certified global tour lower bound after double-count correction.
  calc_instance_lower_bounds_is_certified(t.instance_lower_bound_id) AS is_certified,-- Whether every required stop has one valid local witness and the global double-counting aggregation is closed.
  calc_instance_lower_bounds_base_lower_bound_cost(t.instance_lower_bound_id) AS base_lower_bound_cost,-- Degree-two base lower bound.
  t.required_supplemental_term_count,                                           -- Required additive repair terms.
  calc_instance_lower_bounds_count_of_certified_supplemental_term(t.instance_lower_bound_id) AS count_of_certified_supplemental_terms,-- Certified terms contributing to the adjustment.
  t.supplemental_bound_adjustment,                                              -- Signed sum of certified repair terms.
  calc_instance_lower_bounds_is_supplemental_bound_certified(t.instance_lower_bound_id) AS is_supplemental_bound_certified,-- Whether the required repair terms are all certified.
  t.bound_composition_kind                                                      -- Degree-only or degree-plus-repair composition.
FROM instance_lower_bounds t;

-- ----------------------------------------------------------------------------
-- vw_tsp_bound_terms: Signed additive and constraint terms composing reusable lower-bound certificates.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_bound_terms CASCADE;
CREATE VIEW vw_tsp_bound_terms WITH (security_invoker = ON) AS
SELECT
  t.tsp_bound_term_id,                                                          -- Stable TSPBoundTermId identifier.
  calc_tsp_bound_terms_name(t.tsp_bound_term_id) AS name,                       -- Display alias.
  t.bound_certificate,                                                          -- Owning instance lower bound.
  t.tsp_instance,                                                               -- Owning instance.
  t.tsp_loop,                                                                   -- Loop introducing the term.
  t.term_kind,                                                                  -- Base, insertion, release, parity, or summary term.
  t.quantity,                                                                   -- Witnessed quantity.
  t.unit_weight,                                                                -- Cost per unit.
  t.sign,                                                                       -- Positive or negative contribution.
  calc_tsp_bound_terms_term_value(t.tsp_bound_term_id) AS term_value,           -- Signed additive contribution.
  t.constraint_kind,                                                            -- Constraint witnessed by the term.
  t.constraint_value,                                                           -- Numeric constraint value.
  t.counts_toward_adjustment,                                                   -- Whether TermValue contributes to the supplemental adjustment.
  t.is_certified,                                                               -- Whether the term has a represented witness.
  t.justification                                                               -- Witnessed reason for the term.
FROM tsp_bound_terms t;

-- ----------------------------------------------------------------------------
-- vw_optimality_certificates: Finite-instance optimality certificates. Passing requires a valid Hamiltonian witness, a certified lower bound for the same instance, and equality between candidate cost and lower bound.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_optimality_certificates CASCADE;
CREATE VIEW vw_optimality_certificates WITH (security_invoker = ON) AS
SELECT
  t.optimality_certificate_id,                                                  -- Stable optimality-certificate identifier.
  calc_optimality_certificates_name(t.optimality_certificate_id) AS name,       -- Display alias for the certificate.
  t.candidate_tour,                                                             -- Candidate whose optimality is being certified.
  t.instance_lower_bound,                                                       -- Certified lower bound compared with the candidate cost.
  calc_optimality_certificates_candidate_tsp_instance(t.optimality_certificate_id) AS candidate_tsp_instance,-- Instance owned by the candidate.
  calc_optimality_certificates_lower_bound_tsp_instance(t.optimality_certificate_id) AS lower_bound_tsp_instance,-- Instance owned by the lower-bound certificate.
  calc_optimality_certificates_candidate_travel_cost(t.optimality_certificate_id) AS candidate_travel_cost,-- Derived travel cost of the candidate.
  calc_optimality_certificates_lower_bound_cost(t.optimality_certificate_id) AS lower_bound_cost,-- Certified lower-bound cost.
  calc_optimality_certificates_candidate_is_hamiltonian_cycle_wit(t.optimality_certificate_id) AS candidate_is_hamiltonian_cycle_witness,-- Whether the candidate is a valid Hamiltonian-cycle witness.
  calc_optimality_certificates_lower_bound_is_certified(t.optimality_certificate_id) AS lower_bound_is_certified,-- Whether the lower-bound construction is certified.
  calc_optimality_certificates_is_same_instance(t.optimality_certificate_id) AS is_same_instance,-- Whether candidate and lower bound refer to the same TSP instance.
  calc_optimality_certificates_is_bound_tight(t.optimality_certificate_id) AS is_bound_tight,-- Whether the candidate cost equals the certified lower bound.
  calc_optimality_certificates_is_passing(t.optimality_certificate_id) AS is_passing,-- Whether bound equality certifies this candidate as optimal for the declared finite instance.
  calc_optimality_certificates_scope_claim(t.optimality_certificate_id) AS scope_claim-- Honest scope of the certificate.
FROM optimality_certificates t;

-- ----------------------------------------------------------------------------
-- vw_tsp_execution_runs: Execution attempts against a concrete substrate; blocked and failed runs remain first-class evidence.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_execution_runs CASCADE;
CREATE VIEW vw_tsp_execution_runs WITH (security_invoker = ON) AS
SELECT
  t.tsp_execution_run_id,                                                       -- Stable TSPExecutionRunId identifier.
  calc_tsp_execution_runs_name(t.tsp_execution_run_id) AS name,                 -- Display alias.
  t.tsp_loop,                                                                   -- Loop owning the attempt.
  t.substrate,                                                                  -- Execution substrate.
  t.attempted_at,                                                               -- Attempt timestamp or deterministic run marker.
  t.build_command,                                                              -- Command attempted.
  t.build_succeeded,                                                            -- Whether generation succeeded.
  t.database_initialized,                                                       -- Whether the database initialized.
  t.conformance_succeeded,                                                      -- Whether peer conformance passed.
  t.status,                                                                     -- SUCCEEDED, FAILED, or BLOCKED.
  t.failure_reason,                                                             -- Exact blocking or failure reason.
  calc_tsp_execution_runs_is_successful(t.tsp_execution_run_id) AS is_successful-- Whether all three commissioning stages succeeded.
FROM tsp_execution_runs t;

-- ----------------------------------------------------------------------------
-- vw_tsp_artifacts: Content-addressed artifacts emitted or expected from substrate execution.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_artifacts CASCADE;
CREATE VIEW vw_tsp_artifacts WITH (security_invoker = ON) AS
SELECT
  t.tsp_artifact_id,                                                            -- Stable TSPArtifactId identifier.
  calc_tsp_artifacts_name(t.tsp_artifact_id) AS name,                           -- Display alias.
  t.execution_run,                                                              -- Owning execution run.
  t.artifact_kind,                                                              -- Artifact category.
  t.relative_path,                                                              -- Repository-relative path.
  t.sha256,                                                                     -- Content hash when present.
  t.is_present                                                                  -- Whether the artifact existed.
FROM tsp_artifacts t;

-- ----------------------------------------------------------------------------
-- vw_tsp_conformance_checks: Expected-versus-actual checks for a substrate run.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_conformance_checks CASCADE;
CREATE VIEW vw_tsp_conformance_checks WITH (security_invoker = ON) AS
SELECT
  t.tsp_conformance_check_id,                                                   -- Stable TSPConformanceCheckId identifier.
  calc_tsp_conformance_checks_name(t.tsp_conformance_check_id) AS name,         -- Display alias.
  t.execution_run,                                                              -- Owning execution run.
  t.check_kind,                                                                 -- Check category.
  t.subject_id,                                                                 -- Subject under comparison.
  t.expected_value,                                                             -- Expected value.
  t.actual_value,                                                               -- Observed value.
  t.status,                                                                     -- PASS, FAIL, or BLOCKED.
  calc_tsp_conformance_checks_is_passing(t.tsp_conformance_check_id) AS is_passing-- Whether expected and actual agree.
FROM tsp_conformance_checks t;

-- ----------------------------------------------------------------------------
-- vw_tsp_inference_states: Named immutable snapshots of the current deterministic inference frontier.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_inference_states CASCADE;
CREATE VIEW vw_tsp_inference_states WITH (security_invoker = ON) AS
SELECT
  t.tsp_inference_state_id,                                                     -- Stable TSPInferenceStateId identifier.
  calc_tsp_inference_states_name(t.tsp_inference_state_id) AS name,             -- Display alias.
  t.tsp_instance,                                                               -- Instance under inference.
  t.tsp_loop,                                                                   -- Loop that emitted the state.
  t.state_kind,                                                                 -- Semantic stage.
  t.parent_state_id,                                                            -- Prior state identifier without a self-relationship cycle.
  t.status,                                                                     -- OPEN, CLOSED, or FIXED_POINT.
  t.description                                                                 -- State meaning.
FROM tsp_inference_states t;

-- ----------------------------------------------------------------------------
-- vw_tsp_inference_applications: Individual applications of declared inference rules.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_inference_applications CASCADE;
CREATE VIEW vw_tsp_inference_applications WITH (security_invoker = ON) AS
SELECT
  t.tsp_inference_application_id,                                               -- Stable TSPInferenceApplicationId identifier.
  calc_tsp_inference_applications_name(t.tsp_inference_application_id) AS name, -- Display alias.
  t.inference_state,                                                            -- State receiving the conclusion.
  t.inference_rule,                                                             -- Applied rule.
  t.tsp_loop,                                                                   -- Loop executing the application.
  t.subject_type,                                                               -- Subject category.
  t.subject_id,                                                                 -- Subject identifier.
  t.applicability_passed,                                                       -- Whether preconditions passed.
  t.conclusion,                                                                 -- Locally simple conclusion.
  t.certificate_type,                                                           -- Certificate emitted.
  t.event_kind,                                                                 -- Normalized closure-event kind.
  t.input_state_id,                                                             -- Input state identifier.
  t.output_state_id,                                                            -- Output state identifier.
  t.antecedent_count,                                                           -- Antecedent fact count.
  t.decision_count,                                                             -- Decisions emitted by the event.
  t.event_status                                                                -- APPLIED, FIXED_POINT, or REJECTED.
FROM tsp_inference_applications t;

-- ----------------------------------------------------------------------------
-- vw_tsp_inference_antecedents: Antecedent facts consumed by one inference application.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_inference_antecedents CASCADE;
CREATE VIEW vw_tsp_inference_antecedents WITH (security_invoker = ON) AS
SELECT
  t.tsp_inference_antecedent_id,                                                -- Stable TSPInferenceAntecedentId identifier.
  calc_tsp_inference_antecedents_name(t.tsp_inference_antecedent_id) AS name,   -- Display alias.
  t.inference_application,                                                      -- Owning application.
  t.antecedent_kind,                                                            -- Fact kind.
  t.antecedent_id,                                                              -- Fact identifier.
  t.statement                                                                   -- Antecedent statement.
FROM tsp_inference_antecedents t;

-- ----------------------------------------------------------------------------
-- vw_tsp_edge_states: Epistemically typed state of one edge in one inference snapshot.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_edge_states CASCADE;
CREATE VIEW vw_tsp_edge_states WITH (security_invoker = ON) AS
SELECT
  t.tsp_edge_state_id,                                                          -- Stable TSPEdgeStateId identifier.
  calc_tsp_edge_states_name(t.tsp_edge_state_id) AS name,                       -- Display alias.
  t.inference_state,                                                            -- Owning state.
  t.travel_edge,                                                                -- Edge receiving state.
  t.decision_status,                                                            -- UNKNOWN, SELECTED, FORCED, FORBIDDEN, CONTRADICTED, or SUPERSEDED.
  t.epistemic_status,                                                           -- Why that decision status is justified.
  t.inference_application,                                                      -- Application producing the state.
  calc_tsp_edge_states_is_decided(t.tsp_edge_state_id) AS is_decided,           -- Whether the edge is no longer unknown.
  calc_tsp_edge_states_commitment_rank(t.tsp_edge_state_id) AS commitment_rank, -- Ordered strength in the edge commitment lattice.
  calc_tsp_edge_states_commitment_polarity(t.tsp_edge_state_id) AS commitment_polarity,-- Positive inclusion, zero unknown, or negative exclusion.
  calc_tsp_edge_states_necessity_scope(t.tsp_edge_state_id) AS necessity_scope, -- Scope in which the commitment holds.
  calc_tsp_edge_states_is_terminal_commitment(t.tsp_edge_state_id) AS is_terminal_commitment-- Whether deterministic closure no longer treats the edge as open.
FROM tsp_edge_states t;

-- ----------------------------------------------------------------------------
-- vw_tsp_edge_supports: Witness rows supporting an edge-state conclusion.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_edge_supports CASCADE;
CREATE VIEW vw_tsp_edge_supports WITH (security_invoker = ON) AS
SELECT
  t.tsp_edge_support_id,                                                        -- Stable TSPEdgeSupportId identifier.
  calc_tsp_edge_supports_name(t.tsp_edge_support_id) AS name,                   -- Display alias.
  t.edge_state,                                                                 -- Supported edge-state row.
  t.local_degree_bound,                                                         -- Local bound supplying support.
  t.inference_application,                                                      -- Application consuming the support.
  t.support_kind,                                                               -- Support category.
  t.statement                                                                   -- Support statement.
FROM tsp_edge_supports t;

-- ----------------------------------------------------------------------------
-- vw_tsp_derived_edge_sets: First-class edge sets derived from inference rows rather than supplied route order.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_derived_edge_sets CASCADE;
CREATE VIEW vw_tsp_derived_edge_sets WITH (security_invoker = ON) AS
SELECT
  t.tsp_derived_edge_set_id,                                                    -- Stable TSPDerivedEdgeSetId identifier.
  calc_tsp_derived_edge_sets_name(t.tsp_derived_edge_set_id) AS name,           -- Display alias.
  t.tsp_instance,                                                               -- Owning instance.
  t.inference_state,                                                            -- State that emitted the set.
  t.derivation_kind,                                                            -- Construction used.
  t.edge_count,                                                                 -- Distinct member count.
  t.required_stop_count,                                                        -- Required stops in scope.
  t.total_cost,                                                                 -- Sum of distinct edge costs.
  t.degree_violation_count,                                                     -- Stops not having selected degree two.
  t.connected_component_count,                                                  -- Connected components.
  t.proper_subtour_count,                                                       -- Proper cycle components.
  t.status,                                                                     -- DERIVED_UNCERTIFIED, CONNECTED_DEGREE_TWO, DISCONNECTED_SUBTOURS, or CONTRADICTED.
  calc_tsp_derived_edge_sets_is_connected_degree_two(t.tsp_derived_edge_set_id) AS is_connected_degree_two-- Whether this is one connected degree-two cycle.
FROM tsp_derived_edge_sets t;

-- ----------------------------------------------------------------------------
-- vw_tsp_defect_profiles: Uniform incidence, connectivity, boundary, and cost defects for stops, instances, witnesses, and quotient nodes.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_defect_profiles CASCADE;
CREATE VIEW vw_tsp_defect_profiles WITH (security_invoker = ON) AS
SELECT
  t.tsp_defect_profile_id,                                                      -- Stable TSPDefectProfileId identifier.
  calc_tsp_defect_profiles_name(t.tsp_defect_profile_id) AS name,               -- Display alias.
  t.tsp_instance,                                                               -- Owning instance.
  t.tsp_loop,                                                                   -- Loop emitting the profile.
  t.subject_kind,                                                               -- STOP, EDGE_SET, WITNESS, INSTANCE, or QUOTIENT_NODE.
  t.subject_id,                                                                 -- Polymorphic subject identifier.
  t.required_incidence,                                                         -- Required incident choices.
  t.observed_incidence,                                                         -- Observed incident choices.
  calc_tsp_defect_profiles_incidence_defect(t.tsp_defect_profile_id) AS incidence_defect,-- Absolute incidence deficit or excess.
  t.component_count,                                                            -- Connected components represented by the subject.
  calc_tsp_defect_profiles_connectivity_defect(t.tsp_defect_profile_id) AS connectivity_defect,-- Components beyond the required one.
  t.required_boundary_crossings,                                                -- Required cut or boundary crossings.
  t.observed_boundary_crossings,                                                -- Observed cut or boundary crossings.
  calc_tsp_defect_profiles_boundary_defect(t.tsp_defect_profile_id) AS boundary_defect,-- Missing required boundary crossings.
  t.lower_bound_cost,                                                           -- Current certified lower value.
  t.upper_bound_cost,                                                           -- Current witnessed upper value.
  calc_tsp_defect_profiles_cost_gap(t.tsp_defect_profile_id) AS cost_gap,       -- Upper minus lower value.
  calc_tsp_defect_profiles_defect_vector(t.tsp_defect_profile_id) AS defect_vector,-- Canonical four-coordinate defect vector.
  t.status                                                                      -- Interpretation of the vector.
FROM tsp_defect_profiles t;

-- ----------------------------------------------------------------------------
-- vw_tsp_derived_edge_set_members: Member edges and support counts for a derived edge set.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_derived_edge_set_members CASCADE;
CREATE VIEW vw_tsp_derived_edge_set_members WITH (security_invoker = ON) AS
SELECT
  t.tsp_derived_edge_set_member_id,                                             -- Stable TSPDerivedEdgeSetMemberId identifier.
  calc_tsp_derived_edge_set_members_name(t.tsp_derived_edge_set_member_id) AS name,-- Display alias.
  t.derived_edge_set,                                                           -- Owning edge set.
  t.travel_edge,                                                                -- Member edge.
  t.support_count,                                                              -- Independent support rows.
  t.selected_at_both_endpoints,                                                 -- Whether both endpoint local bounds selected it.
  t.member_status                                                               -- SELECTED, FORCED, or FORBIDDEN.
FROM tsp_derived_edge_set_members t;

-- ----------------------------------------------------------------------------
-- vw_tsp_edge_set_stop_degrees: Selected degree of each required stop in a derived edge set.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_edge_set_stop_degrees CASCADE;
CREATE VIEW vw_tsp_edge_set_stop_degrees WITH (security_invoker = ON) AS
SELECT
  t.tsp_edge_set_stop_degree_id,                                                -- Stable TSPEdgeSetStopDegreeId identifier.
  calc_tsp_edge_set_stop_degrees_name(t.tsp_edge_set_stop_degree_id) AS name,   -- Display alias.
  t.derived_edge_set,                                                           -- Owning set.
  t.instance_stop,                                                              -- Stop under degree check.
  t.selected_degree,                                                            -- Member edges incident to the stop.
  calc_tsp_edge_set_stop_degrees_is_degree_two(t.tsp_edge_set_stop_degree_id) AS is_degree_two-- Whether selected degree is two.
FROM tsp_edge_set_stop_degrees t;

-- ----------------------------------------------------------------------------
-- vw_tsp_spanning_tree_edges: Spanning-tree witness proving connectedness of a selected edge set.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_spanning_tree_edges CASCADE;
CREATE VIEW vw_tsp_spanning_tree_edges WITH (security_invoker = ON) AS
SELECT
  t.tsp_spanning_tree_edge_id,                                                  -- Stable TSPSpanningTreeEdgeId identifier.
  calc_tsp_spanning_tree_edges_name(t.tsp_spanning_tree_edge_id) AS name,       -- Display alias.
  t.derived_edge_set,                                                           -- Owning set.
  t.parent_stop,                                                                -- Parent stop.
  t.child_stop,                                                                 -- Child stop.
  t.travel_edge,                                                                -- Selected edge used by the tree.
  t.depth                                                                       -- Child depth from root.
FROM tsp_spanning_tree_edges t;

-- ----------------------------------------------------------------------------
-- vw_tsp_connected_degree_two_certificates: Certificates that a derived edge set is one connected degree-two cycle.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_connected_degree_two_certificates CASCADE;
CREATE VIEW vw_tsp_connected_degree_two_certificates WITH (security_invoker = ON) AS
SELECT
  t.tsp_connected_degree_two_certificate_id,                                    -- Stable TSPConnectedDegreeTwoCertificateId identifier.
  calc_tsp_connected_degree_two_certificates_name(t.tsp_connected_degree_two_certificate_id) AS name,-- Display alias.
  t.derived_edge_set,                                                           -- Certified set.
  t.required_stop_count,                                                        -- Required stop count.
  t.edge_count,                                                                 -- Selected edge count.
  t.degree_violation_count,                                                     -- Degree violations.
  t.component_count,                                                            -- Connected components.
  t.proper_subtour_count,                                                       -- Proper subtours.
  t.spanning_tree_edge_count,                                                   -- Tree witness edge count.
  calc_tsp_connected_degree_two_certificates_is_passing(t.tsp_connected_degree_two_certificate_id) AS is_passing-- Whether the graph is one connected cycle.
FROM tsp_connected_degree_two_certificates t;

-- ----------------------------------------------------------------------------
-- vw_tsp_route_reconstructions: Ordered cycles reconstructed from certified edge sets.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_route_reconstructions CASCADE;
CREATE VIEW vw_tsp_route_reconstructions WITH (security_invoker = ON) AS
SELECT
  t.tsp_route_reconstruction_id,                                                -- Stable TSPRouteReconstructionId identifier.
  calc_tsp_route_reconstructions_name(t.tsp_route_reconstruction_id) AS name,   -- Display alias.
  t.tsp_instance,                                                               -- Owning instance.
  t.derived_edge_set,                                                           -- Antecedent edge set.
  t.start_stop,                                                                 -- Depot stop.
  t.orientation_rule,                                                           -- Deterministic orientation rule.
  t.required_stop_count,                                                        -- Required stops.
  t.reconstructed_stop_count,                                                   -- Unique stops reconstructed.
  t.reconstructed_leg_count,                                                    -- Legs reconstructed.
  t.total_cost,                                                                 -- Reconstructed cycle cost.
  t.candidate_used_as_antecedent,                                               -- Must remain false.
  t.comparison_candidate,                                                       -- Optional downstream comparison only.
  t.matches_comparison_candidate,                                               -- Whether the reconstructed cycle matches the comparison candidate up to orientation.
  t.status,                                                                     -- RECONSTRUCTED, NOT_EVALUABLE, or CONTRADICTED.
  calc_tsp_route_reconstructions_is_passing(t.tsp_route_reconstruction_id) AS is_passing-- Whether reconstruction closes without a supplied-route antecedent.
FROM tsp_route_reconstructions t;

-- ----------------------------------------------------------------------------
-- vw_tsp_route_reconstruction_steps: Ordered traversal steps emitted from an inferred edge set.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_route_reconstruction_steps CASCADE;
CREATE VIEW vw_tsp_route_reconstruction_steps WITH (security_invoker = ON) AS
SELECT
  t.tsp_route_reconstruction_step_id,                                           -- Stable TSPRouteReconstructionStepId identifier.
  calc_tsp_route_reconstruction_steps_name(t.tsp_route_reconstruction_step_id) AS name,-- Display alias.
  t.route_reconstruction,                                                       -- Owning reconstruction.
  t.step_order,                                                                 -- One-based step order.
  t.from_stop,                                                                  -- Step origin.
  t.to_stop,                                                                    -- Step destination.
  t.travel_edge,                                                                -- Traversed inferred edge.
  t.is_closing_step                                                             -- Whether the step returns to the depot.
FROM tsp_route_reconstruction_steps t;

-- ----------------------------------------------------------------------------
-- vw_tsp_witness_normal_forms: Common semantic normal form for supplied, reconstructed, and contracted cycle or path witnesses.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_witness_normal_forms CASCADE;
CREATE VIEW vw_tsp_witness_normal_forms WITH (security_invoker = ON) AS
SELECT
  t.tsp_witness_normal_form_id,                                                 -- Stable TSPWitnessNormalFormId identifier.
  calc_tsp_witness_normal_forms_name(t.tsp_witness_normal_form_id) AS name,     -- Display alias.
  t.tsp_instance,                                                               -- Owning instance.
  t.tsp_loop,                                                                   -- Loop normalizing the witness.
  t.witness_shape,                                                              -- CYCLE or PATH.
  t.origin_kind,                                                                -- SUPPLIED, RECONSTRUCTED, or CONTRACTED.
  t.source_kind,                                                                -- Historical source projection.
  t.source_id,                                                                  -- Historical source identifier.
  t.boundary_signature,                                                         -- Scope/entry/exit signature for path witnesses.
  t.covered_stop_count,                                                         -- Covered distinct stops.
  t.required_stop_count,                                                        -- Required stops in witness scope.
  t.edge_count,                                                                 -- Witness edge count.
  t.total_cost,                                                                 -- Witness cost.
  t.incidence_defect,                                                           -- Incidence defect.
  t.connectivity_defect,                                                        -- Connectivity defect.
  t.order_defect,                                                               -- Order defect.
  calc_tsp_witness_normal_forms_semantic_key(t.tsp_witness_normal_form_id) AS semantic_key,-- Provenance-independent witness signature.
  calc_tsp_witness_normal_forms_is_valid(t.tsp_witness_normal_form_id) AS is_valid,-- Whether the normal form is a valid cycle or path.
  t.provenance_summary                                                          -- Origin and trust lineage.
FROM tsp_witness_normal_forms t;

-- ----------------------------------------------------------------------------
-- vw_tsp_search_certificates: Derived accounting of route classes, branch decisions, backtracks, and residual ambiguity.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_search_certificates CASCADE;
CREATE VIEW vw_tsp_search_certificates WITH (security_invoker = ON) AS
SELECT
  t.tsp_search_certificate_id,                                                  -- Stable TSPSearchCertificateId identifier.
  calc_tsp_search_certificates_name(t.tsp_search_certificate_id) AS name,       -- Display alias.
  t.tsp_instance,                                                               -- Measured instance.
  t.tsp_loop,                                                                   -- Loop producing the measurement.
  t.derived_edge_set,                                                           -- Structural result supporting the measurement.
  t.question_kind,                                                              -- Discovery or verification question.
  t.initial_route_class_count,                                                  -- Symmetry-reduced classes initially possible.
  t.surviving_route_class_count,                                                -- Classes after deterministic closure.
  t.branch_decision_count,                                                      -- Explicit branch choices.
  t.backtrack_count,                                                            -- Backtracks.
  t.residual_ambiguity_count,                                                   -- Unresolved alternatives.
  t.branching_avoided_pct,                                                      -- Percentage of branch search avoided.
  calc_tsp_search_certificates_route_class_elimination_pct(t.tsp_search_certificate_id) AS route_class_elimination_pct,-- Percentage of route classes removed.
  t.status                                                                      -- CERTIFIED or RESIDUAL_SEARCH.
FROM tsp_search_certificates t;

-- ----------------------------------------------------------------------------
-- vw_tsp_constraint_rounds: Fixed-point rounds for forced and forbidden edge propagation.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_constraint_rounds CASCADE;
CREATE VIEW vw_tsp_constraint_rounds WITH (security_invoker = ON) AS
SELECT
  t.tsp_constraint_round_id,                                                    -- Stable TSPConstraintRoundId identifier.
  calc_tsp_constraint_rounds_name(t.tsp_constraint_round_id) AS name,           -- Display alias.
  t.tsp_instance,                                                               -- Owning instance.
  t.tsp_loop,                                                                   -- Loop emitting the round.
  t.round_order,                                                                -- Round order.
  t.input_state,                                                                -- Input state identifier.
  t.forced_decision_count,                                                      -- New forced decisions.
  t.forbidden_decision_count,                                                   -- New forbidden decisions.
  t.branch_decision_count,                                                      -- Branches taken.
  t.status                                                                      -- ADVANCED or FIXED_POINT.
FROM tsp_constraint_rounds t;

-- ----------------------------------------------------------------------------
-- vw_tsp_constraint_decisions: Replayable forced or forbidden edge decisions with reason codes.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_constraint_decisions CASCADE;
CREATE VIEW vw_tsp_constraint_decisions WITH (security_invoker = ON) AS
SELECT
  t.tsp_constraint_decision_id,                                                 -- Stable TSPConstraintDecisionId identifier.
  calc_tsp_constraint_decisions_name(t.tsp_constraint_decision_id) AS name,     -- Display alias.
  t.constraint_round,                                                           -- Owning closure round.
  t.travel_edge,                                                                -- Decided edge.
  t.instance_stop,                                                              -- Stop exposing the decision.
  t.inference_rule,                                                             -- Rule applied.
  t.decision_status,                                                            -- FORCED or FORBIDDEN.
  t.reason_code,                                                                -- Machine-readable justification.
  t.antecedent_summary,                                                         -- Human-readable antecedents.
  t.is_deterministic                                                            -- Whether no branch was used.
FROM tsp_constraint_decisions t;

-- ----------------------------------------------------------------------------
-- vw_tsp_cluster_boundary_states: Finite undirected entry/exit Hamiltonian-path states for a neighborhood cluster.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_cluster_boundary_states CASCADE;
CREATE VIEW vw_tsp_cluster_boundary_states WITH (security_invoker = ON) AS
SELECT
  t.tsp_cluster_boundary_state_id,                                              -- Stable TSPClusterBoundaryStateId identifier.
  calc_tsp_cluster_boundary_states_name(t.tsp_cluster_boundary_state_id) AS name,-- Display alias.
  t.tsp_instance,                                                               -- Owning instance.
  t.neighborhood,                                                               -- Contracted neighborhood.
  t.entry_stop,                                                                 -- Canonical first boundary stop.
  t.exit_stop,                                                                  -- Canonical second boundary stop.
  t.internal_via_stop,                                                          -- Internal stop between entry and exit.
  t.internal_path_cost,                                                         -- Certified internal path cost.
  t.internal_stop_count,                                                        -- Stops covered inside the cluster.
  t.is_hamiltonian_path,                                                        -- Whether all cluster stops are covered exactly once.
  t.is_dominated,                                                               -- Whether a cheaper state with the same boundary exists.
  t.status,                                                                     -- SURVIVES or DOMINATED.
  t.normalized_witness_id,                                                      -- Witness-normal-form projection identifier.
  calc_tsp_cluster_boundary_states_boundary_signature(t.tsp_cluster_boundary_state_id) AS boundary_signature,-- Scope/entry/exit/coverage/cost signature.
  calc_tsp_cluster_boundary_states_semantic_quotient_key(t.tsp_cluster_boundary_state_id) AS semantic_quotient_key,-- Equivalence key preserving boundary signature and cost.
  t.orientation_multiplicity,                                                   -- Raw directed orientations represented by the undirected state.
  t.is_quotient_representative                                                  -- Whether this state is the canonical quotient representative.
FROM tsp_cluster_boundary_states t;

-- ----------------------------------------------------------------------------
-- vw_tsp_cluster_boundary_state_members: Ordered internal edges supporting a cluster boundary state.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_cluster_boundary_state_members CASCADE;
CREATE VIEW vw_tsp_cluster_boundary_state_members WITH (security_invoker = ON) AS
SELECT
  t.tsp_cluster_boundary_state_member_id,                                       -- Stable TSPClusterBoundaryStateMemberId identifier.
  calc_tsp_cluster_boundary_state_members_name(t.tsp_cluster_boundary_state_member_id) AS name,-- Display alias.
  t.cluster_boundary_state,                                                     -- Owning state.
  t.travel_edge,                                                                -- Internal path edge.
  t.member_order                                                                -- Path order.
FROM tsp_cluster_boundary_state_members t;

-- ----------------------------------------------------------------------------
-- vw_tsp_cluster_contraction_certificates: Finite-fixture certificates measuring neighborhood-state contraction.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_cluster_contraction_certificates CASCADE;
CREATE VIEW vw_tsp_cluster_contraction_certificates WITH (security_invoker = ON) AS
SELECT
  t.tsp_cluster_contraction_certificate_id,                                     -- Stable TSPClusterContractionCertificateId identifier.
  calc_tsp_cluster_contraction_certificates_name(t.tsp_cluster_contraction_certificate_id) AS name,-- Display alias.
  t.tsp_instance,                                                               -- Owning instance.
  t.neighborhood,                                                               -- Neighborhood for local scope; null for instance composition.
  t.scope_kind,                                                                 -- NEIGHBORHOOD or INSTANCE_COMPOSITION.
  t.raw_internal_order_count,                                                   -- Raw internal orders.
  t.surviving_boundary_state_count,                                             -- States after canonicalization/dominance.
  t.raw_combination_count,                                                      -- Raw cross-cluster combinations.
  t.contracted_combination_count,                                               -- Boundary-state combinations.
  t.reduction_pct,                                                              -- Measured reduction.
  t.is_passing,                                                                 -- Whether coverage and cost preservation checks pass.
  t.scope_claim,                                                                -- Finite scope of the certificate.
  t.equivalence_relation,                                                       -- Explicit semantic equivalence relation.
  t.quotient_class_count                                                        -- Number of equivalence classes.
FROM tsp_cluster_contraction_certificates t;

-- ----------------------------------------------------------------------------
-- vw_tsp_inference_rules: Declared structural inference contracts, including soundness, completeness, runtime, memory, applicability, and certificate shape.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_inference_rules CASCADE;
CREATE VIEW vw_tsp_inference_rules WITH (security_invoker = ON) AS
SELECT
  t.tsp_inference_rule_id,                                                      -- Stable inference-rule identifier.
  calc_tsp_inference_rules_name(t.tsp_inference_rule_id) AS name,               -- Human-readable inference-rule label.
  t.display_name,                                                               -- Human-readable inference-rule name.
  t.inference_layer,                                                            -- Pipeline layer in which the rule applies.
  t.implementation_status,                                                      -- Whether the rule is executable in the current rulebook.
  t.soundness,                                                                  -- Current soundness claim.
  t.completeness,                                                               -- Current completeness claim.
  t.runtime_class,                                                              -- Declared asymptotic runtime for the represented step.
  t.memory_class,                                                               -- Declared asymptotic memory for the represented step.
  t.applicability,                                                              -- Preconditions for using the rule.
  t.certificate_type,                                                           -- Witness or certificate emitted by the rule.
  t.description                                                                 -- Operational meaning of the rule.
FROM tsp_inference_rules t;

-- ----------------------------------------------------------------------------
-- vw_tsp_frontier_obligations: Typed ledger of open and closed semantic frontier obligations. Imported dependencies are used only when an external provider conclusion is actually consumed.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_frontier_obligations CASCADE;
CREATE VIEW vw_tsp_frontier_obligations WITH (security_invoker = ON) AS
SELECT
  t.tsp_frontier_obligation_id,                                                 -- Stable frontier-obligation identifier.
  calc_tsp_frontier_obligations_name(t.tsp_frontier_obligation_id) AS name,     -- Human-readable obligation label.
  t.display_name,                                                               -- Human-readable frontier-obligation name.
  t.obligation_kind,                                                            -- Typed class: imported dependency, inference, certificate, substrate, generalization, or residual search.
  t.status,                                                                     -- OPEN, CLOSED, BLOCKED, DEFERRED, or FALSIFIED.
  t.inference_rule,                                                             -- Inference contract primarily responsible for closure.
  t.opened_by_loop,                                                             -- Loop that exposed this frontier obligation.
  t.closed_by_loop,                                                             -- Loop that closed the obligation, when closed.
  t.trust_disposition,                                                          -- How the obligation is expected to close or where trust remains.
  t.closure_criterion,                                                          -- Concrete, auditable condition required for closure.
  t.certificate_type,                                                           -- Certificate expected or emitted by closure.
  calc_tsp_frontier_obligations_is_imported_dependency(t.tsp_frontier_obligation_id) AS is_imported_dependency,-- Whether this row consumes an external provider conclusion.
  calc_tsp_frontier_obligations_is_closed(t.tsp_frontier_obligation_id) AS is_closed-- Whether the frontier obligation is closed.
FROM tsp_frontier_obligations t;

-- ----------------------------------------------------------------------------
-- vw_tsp_loops: Named semantic loops that establish the initial Traveling Salesman architecture.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_loops CASCADE;
CREATE VIEW vw_tsp_loops WITH (security_invoker = ON) AS
SELECT
  t.tsp_loop_id,                                                                -- Stable loop identifier.
  calc_tsp_loops_name(t.tsp_loop_id) AS name,                                   -- Human-readable loop label.
  t.loop_order,                                                                 -- Global Effortless Math loop number.
  t.display_name,                                                               -- Human-readable loop name.
  t.status,                                                                     -- Completion status of this loop.
  t.primary_inference_rule,                                                     -- Primary inference contract advanced by the loop.
  t.new_concept,                                                                -- Semantic structure added by the loop.
  t.witness_summary,                                                            -- Concrete evidence produced by the loop.
  t.next_frontier,                                                              -- Unclosed edge exposed by the loop.
  t.planned_closure_criterion,                                                  -- Auditable condition declared before loop execution.
  t.before_state,                                                               -- Frontier state recorded before loop execution.
  t.after_state,                                                                -- Observed state after execution.
  t.completion_disposition                                                      -- CLOSED, BLOCKED, FALSIFIED, or DEFERRED.
FROM tsp_loops t;

-- ----------------------------------------------------------------------------
-- vw_tsp_convergence_measurements: Measurements testing whether surface concepts compress onto a stable predicate basis.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_convergence_measurements CASCADE;
CREATE VIEW vw_tsp_convergence_measurements WITH (security_invoker = ON) AS
SELECT
  t.tsp_convergence_measurement_id,                                             -- Stable TSPConvergenceMeasurementId identifier.
  calc_tsp_convergence_measurements_name(t.tsp_convergence_measurement_id) AS name,-- Display alias.
  t.tsp_loop,                                                                   -- Loop emitting the measurement.
  t.measurement_kind,                                                           -- Baseline, reduction, stability, or final convergence measurement.
  t.surface_concept_count_before,                                               -- Surface vocabulary count before quotienting.
  t.primitive_count_after,                                                      -- Active primitive count after reduction.
  t.new_primitive_count,                                                        -- New primitives introduced by this loop.
  t.derived_alias_count,                                                        -- Named derived concepts retained above the basis.
  t.physical_table_count,                                                       -- Canonical physical table count at this loop.
  calc_tsp_convergence_measurements_semantic_compression_pct(t.tsp_convergence_measurement_id) AS semantic_compression_pct,-- Surface-to-basis reduction percentage.
  t.novel_term,                                                                 -- Predicate coined or stabilized by the loop.
  t.prediction_status,                                                          -- NOT_TESTED, EARLY_SUPPORT, COUNTEREVIDENCE, or SUPPORTED_FOR_CURRENT_DOMAIN.
  t.notes                                                                       -- Scope and interpretation.
FROM tsp_convergence_measurements t;

-- ----------------------------------------------------------------------------
-- vw_tsp_concept_registry: Registry of primitive, derived, coined, and historical concepts with explicit basis expressions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_concept_registry CASCADE;
CREATE VIEW vw_tsp_concept_registry WITH (security_invoker = ON) AS
SELECT
  t.tsp_concept_id,                                                             -- Stable TSPConceptId identifier.
  calc_tsp_concept_registry_name(t.tsp_concept_id) AS name,                     -- Display alias.
  t.display_name,                                                               -- Human-readable concept name.
  t.concept_kind,                                                               -- PRIMITIVE, DERIVED_ALIAS, COINED_PREDICATE, or HISTORICAL_PROJECTION.
  t.basis_expression,                                                           -- Definition over the eight primitive predicates.
  t.arity,                                                                      -- Declared argument count for the concept.
  t.source_tables,                                                              -- Comma-separated historical source projections.
  t.introduced_by_loop,                                                         -- Loop introducing or registering the concept.
  t.superseded_by_concept,                                                      -- Canonical coined concept replacing this surface name, when applicable.
  t.status                                                                      -- ACTIVE_PRIMITIVE, ACTIVE_DERIVED, or HISTORICAL_PROJECTION.
FROM tsp_concept_registry t;

-- ----------------------------------------------------------------------------
-- vw_search_metrics: Quantitative record of how much combinatorial search remains after each represented inference stage.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_search_metrics CASCADE;
CREATE VIEW vw_search_metrics WITH (security_invoker = ON) AS
SELECT
  t.search_metric_id,                                                           -- Stable search-metric identifier.
  calc_search_metrics_name(t.search_metric_id) AS name,                         -- Display alias for the metric row.
  t.tsp_instance,                                                               -- TSP instance being measured.
  t.tsp_loop,                                                                   -- Loop that produced the measurement.
  t.search_question,                                                            -- Exact question whose remaining branch count is being measured.
  t.candidate_tour,                                                             -- Candidate involved when measuring verification rather than route discovery.
  t.raw_node_count,                                                             -- Required stop count before inference.
  t.raw_edge_count,                                                             -- Canonical edge count before inference.
  t.forced_edge_count,                                                          -- Edges forced by represented inference.
  t.forbidden_edge_count,                                                       -- Edges forbidden by represented inference.
  t.symmetry_class_count,                                                       -- Route classes after fixing depot and reversal symmetry.
  t.component_contraction_count,                                                -- Components or clusters contracted.
  t.branch_count_before,                                                        -- Branches before the current inference stage.
  t.branch_count_after,                                                         -- Branches after the current inference stage.
  t.backtrack_count,                                                            -- Backtracks consumed by search.
  t.residual_ambiguity_count,                                                   -- Remaining unresolved route classes or boundary states.
  calc_search_metrics_search_elimination_pct(t.search_metric_id) AS search_elimination_pct,-- Percentage of branches removed without search.
  t.status                                                                      -- Interpretation of the metric row.
FROM search_metrics t;

-- ----------------------------------------------------------------------------
-- vw_tsp_invariant_checks: Rulebook-native acceptance checks comparing expected raw outcomes to derived candidate-tour fields.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tsp_invariant_checks CASCADE;
CREATE VIEW vw_tsp_invariant_checks WITH (security_invoker = ON) AS
SELECT
  t.tsp_invariant_check_id,                                                     -- Stable invariant-check identifier.
  calc_tsp_invariant_checks_name(t.tsp_invariant_check_id) AS name,             -- Human-readable invariant label.
  t.display_name,                                                               -- Human-readable invariant name.
  t.candidate_tour,                                                             -- Candidate tour under test.
  t.expected_hamiltonian_cycle_witness,                                         -- Expected derived route-validity result.
  calc_tsp_invariant_checks_actual_hamiltonian_cycle_witness(t.tsp_invariant_check_id) AS actual_hamiltonian_cycle_witness,-- Derived route-validity result from the candidate-tour view.
  t.expected_optimality_proved,                                                 -- Expected optimality-certificate status.
  calc_tsp_invariant_checks_actual_optimality_proved(t.tsp_invariant_check_id) AS actual_optimality_proved,-- Derived optimality-certificate status from the candidate-tour view.
  t.expected_total_travel_cost,                                                 -- Expected sum of represented valid leg costs.
  calc_tsp_invariant_checks_actual_total_travel_cost(t.tsp_invariant_check_id) AS actual_total_travel_cost,-- Derived total tour cost from the candidate-tour view.
  calc_tsp_invariant_checks_is_hamiltonian_status_correct(t.tsp_invariant_check_id) AS is_hamiltonian_status_correct,-- Whether expected and actual route validity agree.
  calc_tsp_invariant_checks_is_optimality_status_correct(t.tsp_invariant_check_id) AS is_optimality_status_correct,-- Whether expected and actual optimality status agree.
  calc_tsp_invariant_checks_is_cost_correct(t.tsp_invariant_check_id) AS is_cost_correct,-- Whether expected and actual total cost agree.
  calc_tsp_invariant_checks_is_passing(t.tsp_invariant_check_id) AS is_passing  -- Whether all represented expectations agree with derived values.
FROM tsp_invariant_checks t;

